queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?goal_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:goal_id ?cg . ?child a :Goals ; p:id ?cg . ?l p:sales_position_id ?pg . ?parent a :Sales_Positions ; p:id ?pg . } GROUP BY ?child }
  ?child p:goal_type ?goal_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Sales_Positions } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?position_name ?goal_type WHERE {
  ?sales_positions_goals a :Sales_Positions_Goals .
  ?goals a :Goals .
  ?sales_positions_goals p:hasGoals ?goals .
  ?sales_positions a :Sales_Positions .
  ?sales_positions_goals p:hasSales_Positions ?sales_positions .
  ?sales_positions p:position_name ?position_name .
  ?goals p:goal_type ?goal_type .
} }
  collective: { SELECT ?goal_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:goal_id ?cg . ?child a :Goals ; p:id ?cg . ?l p:sales_position_id ?pg . ?parent a :Sales_Positions ; p:id ?pg . } GROUP BY ?child }
  ?child p:goal_type ?goal_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Sales_Positions } }
  FILTER(?nf = ?total)
} }
}
